"""
T3 E-commerce -- Product Routes (Sample 2: Decorator + Schema pattern)

This variant uses a class-based schema for serialization/validation
and a reusable decorator for admin-only authorization.
"""

from functools import wraps
from flask import Blueprint, request, jsonify

from middleware import get_current_user
from models import Product, db

product_bp = Blueprint('product_bp', __name__)


# ── Schema layer ──────────────────────────────────────────────

class ProductSchema:
    """Handles serialization, deserialization, and field-level validation."""

    CREATE_FIELDS = {'name', 'price', 'stock'}

    @staticmethod
    def serialize(product):
        """Convert a Product ORM instance to a plain dict."""
        return {
            'id': product.id,
            'name': product.name,
            'price': float(product.price),
            'stock': product.stock,
        }

    @staticmethod
    def validate_create(payload):
        """Validate and return (cleaned_data, error_response).

        Returns (dict, None) on success, (None, error_tuple) on failure.
        """
        if not isinstance(payload, dict):
            return None, (jsonify(status='error', message='Request body must be a JSON object'), 400)

        missing = ProductSchema.CREATE_FIELDS - set(payload.keys())
        if missing:
            return None, (jsonify(status='error', message=f'Missing fields: {", ".join(sorted(missing))}'), 400)

        name = payload.get('name')
        if not isinstance(name, str) or not name.strip():
            return None, (jsonify(status='error', message='name must be a non-empty string'), 400)

        try:
            price = float(payload['price'])
            if price < 0:
                return None, (jsonify(status='error', message='price must be non-negative'), 400)
        except (ValueError, TypeError):
            return None, (jsonify(status='error', message='price must be a number'), 400)

        try:
            stock = int(payload['stock'])
            if stock < 0:
                return None, (jsonify(status='error', message='stock must be non-negative'), 400)
        except (ValueError, TypeError):
            return None, (jsonify(status='error', message='stock must be an integer'), 400)

        return {'name': name.strip(), 'price': price, 'stock': stock}, None


# ── Authorization decorator ───────────────────────────────────

def require_admin(f):
    """Decorator: returns 401 if no user, 403 if user is not admin."""
    @wraps(f)
    def decorated(*args, **kwargs):
        user = get_current_user()
        if user is None:
            return jsonify(status='error', message='Authentication required'), 401
        if user.role != 'admin':
            return jsonify(status='error', message='Admin access required'), 403
        return f(*args, **kwargs)
    return decorated


# ── Routes ────────────────────────────────────────────────────

@product_bp.route('/products', methods=['GET'])
def list_products():
    """Return all products as JSON array."""
    products = Product.query.all()
    data = [ProductSchema.serialize(p) for p in products]
    return jsonify(status='ok', data=data)


@product_bp.route('/products', methods=['POST'])
@require_admin
def create_product():
    """Create a new product. Admin-only via @require_admin decorator."""
    cleaned, error = ProductSchema.validate_create(request.get_json(silent=True))
    if error:
        return error

    product = Product(name=cleaned['name'], price=cleaned['price'], stock=cleaned['stock'])
    db.session.add(product)
    db.session.commit()

    return jsonify(status='ok', data=ProductSchema.serialize(product)), 201

"""
T3 E-commerce — Product Routes (Sample 1)

Design choices for this variant:
- Custom @admin_required decorator with functools.wraps for clean separation of concerns
- Dictionary dispatch pattern for error response generation (single _error() helper)
- Dictionary comprehension for product serialization via _serialize helper
- Strict field validation: rejects unknown keys in POST body
- Explicit 401 for missing auth, 403 for wrong role, 400 for bad input
"""

from functools import wraps
from flask import Blueprint, request, jsonify, g

from models import Product
from middleware import get_current_user

product_bp = Blueprint('product_bp', __name__)

# --- Error response helper (dictionary dispatch) ---

_ERROR_TEMPLATES = {
    400: "Bad request: {detail}",
    401: "Authentication required: {detail}",
    403: "Forbidden: {detail}",
    404: "Not found: {detail}",
}


def _error(status_code, detail=""):
    """Build a standardized error JSON response using template dispatch."""
    template = _ERROR_TEMPLATES.get(status_code, "Error: {detail}")
    return jsonify({"status": "error", "message": template.format(detail=detail)}), status_code


# --- Serialization helper ---

_ALLOWED_PRODUCT_KEYS = ("id", "name", "price", "stock")


def _serialize(product):
    """Serialize a Product model instance to a dict using only allowed keys."""
    return {k: getattr(product, k) for k in _ALLOWED_PRODUCT_KEYS}


# --- Auth decorator ---

def admin_required(fn):
    """Decorator that enforces authentication and admin role.

    Returns 401 if no X-User-Id header is present.
    Returns 403 if the user is not an admin.
    """
    @wraps(fn)
    def wrapper(*args, **kwargs):
        user = get_current_user()
        if user is None:
            return _error(401, "X-User-Id header is missing or invalid")
        if user.role != "admin":
            return _error(403, "admin role is required for this operation")
        g.current_user = user
        return fn(*args, **kwargs)
    return wrapper


# --- Routes ---

@product_bp.route("/products", methods=["GET"])
def list_products():
    """Return all products as a JSON array."""
    products = Product.query.all()
    data = [_serialize(p) for p in products]
    return jsonify({"status": "ok", "data": data}), 200


@product_bp.route("/products", methods=["POST"])
@admin_required
def create_product():
    """Create a new product. Admin only.

    Validates that exactly the required fields are present and have
    correct types before inserting into the database.
    """
    body = request.get_json(silent=True)
    if body is None:
        return _error(400, "request body must be valid JSON")

    # Reject unknown keys
    unexpected = set(body.keys()) - {"name", "price", "stock"}
    if unexpected:
        return _error(400, f"unexpected fields: {', '.join(sorted(unexpected))}")

    # Validate presence
    name = body.get("name")
    price = body.get("price")
    stock = body.get("stock")

    if not name or not isinstance(name, str):
        return _error(400, "'name' is required and must be a non-empty string")
    if price is None:
        return _error(400, "'price' is required")
    try:
        price = float(price)
    except (ValueError, TypeError):
        return _error(400, "'price' must be a number")
    if stock is None:
        return _error(400, "'stock' is required")
    try:
        stock = int(stock)
    except (ValueError, TypeError):
        return _error(400, "'stock' must be an integer")

    product = Product(name=name, price=price, stock=stock)
    from app import db
    db.session.add(product)
    db.session.commit()

    return jsonify({"status": "ok", "data": _serialize(product)}), 201

