    result = db.session.execute(
        text("UPDATE product SET stock = stock - :qty WHERE id = :pid AND stock >= :qty"),
        {"qty": quantity, "pid": product_id}
    )
    db.session.commit()

    if result.rowcount == 0:
        # Stock was insufficient (either product gone or stock < quantity)
        return _error(400, "insufficient stock for this product")

    # Refresh product to get updated price for total_price calculation
    db.session.refresh(product)
    total_price = product.price * quantity

    order = Order(
        user_id=user.id,
        product_id=product_id,
        quantity=quantity,
        total_price=total_price,
        origin=origin,
    )
    db.session.add(order)
    db.session.commit()

    return jsonify({"status": "ok", "data": _serialize(order)}), 201


